class Solution {
    public int longestSemiRepetitiveSubstring(String s) {
        int n = s.length();
        int maxLen = 0;
        for (int i = 0; i < n; i++) {
            int count = 1;
            boolean hasRepeat = false;
            for (int j = i + 1; j < n; j++) {
                if (s.charAt(j) == s.charAt(j - 1)) {
                    if (hasRepeat) break;
                    hasRepeat = true;
                } else {
                    count++;
                }
            }
            maxLen = Math.max(maxLen, count);
        }
        return maxLen;
    }
}
